local TD = TD.td1madao["ydj_dst_td1madao"] TD.createFn("delta", function(num, delta, max)     if TD.isNum(num) and TD.isNum(delta) then         local value = num + delta         if value < 0 then             value = 0         end         if TD.isNum(max) and value > max then             value = max         end         return value     end     return 0 end) TD.createFn("setMax", function(num, max)     if TD.isNum(num) then         local value = num         if value < 0 then             value = 0         end         if TD.isNum(max) and value < max then             value = max         end         return value     end     return 0 end) TD.createFn("setMin", function(num, min)     if TD.isNum(num) then         local value = num         if value < 0 then             value = 0         end         if TD.isNum(min) and value > min then             value = min         end         return value     end     return 0 end) TD.createFn("setMax2", function(num, max)     if TD.isNum(num) then         local value = num         if TD.isNum(max) and value < max then             value = max         end         return value     end     return 0 end) TD.createFn("setMin2", function(num, min)     if TD.isNum(num) then         local value = num         if TD.isNum(min) and value > min then             value = min         end         return value     end     return 0 end) TD.createFn("minus", function(num)     return TD.delta(num, -1) end) TD.createFn("loadCurrentAttribute", function(inst)     if not inst then         return     end     local OnPreLoad = function(inst, data)         if data ~= nil and inst ~= nil then             if data.health and data.health.health then inst.currentHealth = data.health.health end             if data.hunger and data.hunger.hunger then inst.currentHunger = data.hunger.hunger end             if data.sanity and data.sanity.current then inst.currentSanity = data.sanity.current end         end     end          if inst.OnPreLoad then         local old = inst.OnPreLoad         inst.OnPreLoad = function(inst, data)             old(inst, data)             OnPreLoad(inst, data)         end     else         inst.OnPreLoad = OnPreLoad     end end) TD.createFn("maxHealth", function(inst, num)     if not TD.server() or not inst or not TD.isPos(num) then         return     end     TD.hasC(inst, "health", function(self)         self.maxhealth = math.ceil(num)         if TD.isPos(inst.currentHealth) then             self.currenthealth = inst.currentHealth             inst.currentHealth = nil         end         if self.currenthealth > self.maxhealth then             self.currenthealth = self.maxhealth         end         if TD.dst() then             self:ForceUpdateHUD()         else             self:DoDelta(0)         end     end) end) TD.createFn("maxHunger", function(inst, num)     if not TD.server() or not inst or not TD.isPos(num) then         return     end     TD.hasC(inst, "hunger", function(self)         self.max = math.ceil(num)         if TD.isPos(inst.currentHunger) then             self.current = inst.currentHunger             inst.currentHunger = nil         end         if self.current > self.max then             self.current = self.max         end     end) end) TD.createFn("maxSanity", function(inst, num)     if not TD.server() or not inst or not TD.isPos(num) then         return     end     TD.hasC(inst, "sanity", function(self)         self.max = math.ceil(num)         if TD.isPos(inst.currentSanity) then             self.current = inst.currentSanity             inst.currentSanity = nil         end         if self.current > self.max then             self.current = self.max         end         self:DoDelta(0)     end) end) TD.createFn("damage", function(inst, num)     if not TD.server() or not inst or not TD.isPos(num) then         return     end     TD.hasC(inst, "combat", function(self)         self.damagemultiplier = num or self.damagemultiplier                  if TD.ds() and self.AddDamageModifier then             self:AddDamageModifier(TD.CHAR, self.damagemultiplier - 1)         end     end) end) TD.createFn("speed", function(inst, num)     if not inst or not TD.isPos(num) then         return     end     TD.hasC(inst, "locomotor", function(self)         self.walkspeed = TUNING.WILSON_WALK_SPEED * num         self.runspeed = TUNING.WILSON_RUN_SPEED * num     end) end) TD.createFn("flushAtt", function(inst, param)     if inst and TD.isTab(param) and TD.isServer() then         if param.health then             TD.maxHealth(inst, param.health)         end         if param.hunger then             TD.maxHunger(inst, param.hunger)         end         if param.sanity then             TD.maxSanity(inst, param.sanity)         end         if param.damage then             TD.damage(inst, param.damage)         end         if param.speed then             TD.speed(inst, param.speed)         end     end end) TD.createFn("cycles", function()     return (TD.GetWorld().state.cycles + 1) or 1 end) TD.createFn("writeAtt", function(inst, param)     if inst and TD.isTab(param) and TD.isServer() then         TD.getC(inst, "health", function(comp)             if TD.isPos(param.health) then                 comp:SetMaxHealth(param.health)             end         end)         TD.getC(inst, "hunger", function(comp)             if TD.isPos(param.hunger) then                 comp:SetMax(param.hunger)             end         end)         TD.getC(inst, "sanity", function(comp)             if TD.isPos(param.sanity) then                 comp:SetMax(param.sanity)             end         end)         if TD.isPos(param.damage) then             TD.damage(inst, param.damage)         end         if TD.isPos(param.speed) then             TD.speed(inst, param.speed)         end     end end) TD.createFn("randomInTab", function(myTable)     if TD.isTab(myTable) then         return myTable[math.random(#myTable)]     end     return nil end) 